#include<bits/stdc++.h>
using namespace std;
long long root[100010],ans[100010],n,m;
struct node
{
    long long d,p,l;
    bool operator<(const node&b)const
    {
        return d>b.d;
    }
}a[100010];
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long sum,cnt;
    }a[3200010];
    long long cnt;
    segment_tree():cnt(0){}
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum=a[x].cnt=0;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        return x;
    }
    long long update(long long x,long long p,long long v)
    {
        long long now=++cnt;
        a[now]=a[x];
        a[now].sum+=p*v;
        a[now].cnt+=v;
        if(a[x].l==a[x].r)
        {
            return now;
        }
        long long mid=(a[x].l+a[x].r)>>1;
        if(p<=mid)
        {
            a[now].lson=update(a[x].lson,p,v);
        }
        else
        {
            a[now].rson=update(a[x].rson,p,v);
        }
        return now;
    }
    long long query(long long x,long long k)
    {
        if(a[x].l==a[x].r)
        {
            return a[x].l*k;
        }
        if(k<=a[a[x].lson].cnt)
        {
            return query(a[x].lson,k);
        }
        else
        {
            return a[a[x].lson].sum+query(a[x].rson,k-a[a[x].lson].cnt);
        }
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld%lld",&a[i].d,&a[i].p,&a[i].l);
    }
    sort(a+1,a+1+n);
    root[0]=t.init(1,100000);
    for(long long i=1;i<=n;i++)
    {
        root[i]=t.update(root[i-1],a[i].p,a[i].l);
    }
    while(m--)
    {
        long long g,lim;
        scanf("%lld%lld",&g,&lim);
        long long l=1,r=n,best=-1;
        while(l<=r)
        {
            long long mid=(l+r)>>1;
            long long tmp=t.query(root[mid],lim);
            if(tmp<=g&&t.a[root[mid]].cnt>=lim)
            {
                r=mid-1;
                best=mid;
            }
            else
            {
                l=mid+1;
            }
        }
        printf("%lld\n",(best==-1?-1:a[best].d));
    }
    return 0;
}
